export type PlateId =
  | 'pacific'
  | 'north-american'
  | 'eurasian'
  | 'african'
  | 'south-american'
  | 'antarctic'
  | 'indo-australian'

export type ContinentId =
  | 'north-america'
  | 'south-america'
  | 'eurasia'
  | 'africa'
  | 'india'
  | 'australia'
  | 'antarctica'

export interface PlateAtEra {
  id: PlateId
  /**
   * Polygon vertices as [latitude, longitude] degree pairs. Order is treated
   * as counterclockwise when viewed from outside the sphere (the standard
   * three.js front-face winding). If a plate renders inside-out at runtime,
   * reverse the array.
   *
   * Range: latitude [-90, 90], longitude [-180, 180]. Each plate has 12
   * vertices in v1. Counts are uniform across eras so tweenPlates can pair
   * vertices index-by-index.
   */
  vertices: ReadonlyArray<readonly [number, number]>
}

export interface ContinentAtEra {
  id: ContinentId
  /**
   * Multi-polygon: each continent can have multiple disjoint pieces
   * (e.g., North America = mainland + Greenland + Caribbean islands).
   * Each piece is an outer ring of [lat, lng] degree pairs.
   *
   * For SLERP tween between eras, piece count and per-piece vertex counts
   * must match across eras (so vertex i of piece j at era E pairs with the
   * same indices at era E+1).
   */
  polygons: ReadonlyArray<ReadonlyArray<readonly [number, number]>>
}

export interface Era {
  id: 'pangaea' | 'late-jurassic' | 'late-cretaceous' | 'eocene' | 'present' | 'future'
  name: string
  mya: number
  descriptionBeginner: string
  descriptionStandard: string
  descriptionAdvanced: string
  plates: ReadonlyArray<PlateAtEra>
  continents: ReadonlyArray<ContinentAtEra>
}

// Vertex data note: plate boundaries reflect real tectonic plate extents
// (extending into oceans). Continent polygons are separate, representing
// the visible landmasses at each era.

